UPDATE inspection_standard
inspection_name = #{inspectionName}, part_code = #{partCode}, part_name = #{partName}, implementation_cycle = #{implementationCycle}, cycle_unit = #{cycleUnit}, data_type = #{dataType}, signal_type = #{signalType}, implementation_method = #{implementationMethod}, inspection_content = #{inspectionContent}, inspection_part = #{inspectionPart}, qualitative_standard = #{qualitativeStandard}, standard_category = #{standardCategory}, quantitative_standard = #{quantitativeStandard}, unit_of_measurement = #{unitOfMeasurement}, profession = #{profession}, upper_limit = #{upperLimit}, lower_limit = #{lowerLimit}, id_location_code = #{idLocationCode}, id_location_name = #{idLocationName}, updated_at = #{updatedAt},
WHERE id = #{id}

mapper.select:
SELECT ins.id, ins.inspection_name AS inspectionName, ins.part_code AS partCode, ins.part_name AS partName,
       ins.implementation_cycle AS implementationCycle, ins.cycle_unit AS cycleUnit, ins.data_type AS dataType,
       ins.signal_type AS signalType, ins.implementation_method AS implementationMethod,
       ins.inspection_content AS inspectionContent, ins.inspection_part AS inspectionPart,
       ins.qualitative_standard AS qualitativeStandard, ins.standard_category AS standardCategory,
       ins.quantitative_standard AS quantitativeStandard, ins.unit_of_measurement AS unitOfMeasurement,
       ins.profession, ins.upper_limit AS upperLimit, ins.lower_limit AS lowerLimit,
       ins.id_location_code AS idLocationCode, ins.id_location_name AS idLocationName,
       ins.creator_id AS creatorId, ins.created_at AS createdAt, ins.updated_at AS updatedAt,
       su.real_name AS creatorName, su.username AS creatorUsername
FROM inspection_standard ins
LEFT JOIN sys_user su ON ins.creator_id = su.id

    AND ins.creator_id = #{creatorId}
    AND ins.inspection_name LIKE CONCAT('%', #{inspectionName}, '%')
    AND ins.part_code = #{partCode}
    AND ins.part_code IN #{code}
    AND ins.part_name LIKE CONCAT('%', #{partName}, '%')
    AND ins.cycle_unit = #{cycleUnit}
    AND ins.data_type = #{dataType}
    AND ins.signal_type = #{signalType}
    AND ins.implementation_method = #{implementationMethod}
    AND ins.standard_category = #{standardCategory}
    AND ins.unit_of_measurement = #{unitOfMeasurement}
    AND ins.profession = #{profession}

ORDER BY ins.id DESC
